import{_ as a,o as n,c as r,a2 as s}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"運價與貨櫃航運獲利連動","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/航運產業/05_航運週期與景氣判斷/05-3_運價與貨櫃航運獲利連動.md","filePath":"Deep32Q知識庫/產業洞察/航運產業/05_航運週期與景氣判斷/05-3_運價與貨櫃航運獲利連動.md"}'),e={name:"Deep32Q知識庫/產業洞察/航運產業/05_航運週期與景氣判斷/05-3_運價與貨櫃航運獲利連動.md"};function l(d,t,i,o,h,p){return n(),r("div",null,[...t[0]||(t[0]=[s(`<h1 id="運價與貨櫃航運獲利連動" tabindex="-1">運價與貨櫃航運獲利連動 <a class="header-anchor" href="#運價與貨櫃航運獲利連動" aria-label="Permalink to &quot;運價與貨櫃航運獲利連動&quot;">​</a></h1><h2 id="📊-運價→營收→獲利的傳導機制" tabindex="-1">📊 運價→營收→獲利的傳導機制 <a class="header-anchor" href="#📊-運價→營收→獲利的傳導機制" aria-label="Permalink to &quot;📊 運價→營收→獲利的傳導機制&quot;">​</a></h2><p>貨櫃航運的獲利鏈條為：<strong>即期/合約運價 → 營收 → 毛利 → EBITDA → 淨利</strong>。其中運價是最先波動、影響最直接的變數。</p><h3 id="傳導鏈條" tabindex="-1">傳導鏈條 <a class="header-anchor" href="#傳導鏈條" aria-label="Permalink to &quot;傳導鏈條&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>運價變動（SCFI/WCI/FBX）</span></span>
<span class="line"><span>    ↓ 1–2 個月滯後</span></span>
<span class="line"><span>營收（TEU × 平均運價）</span></span>
<span class="line"><span>    ↓ 扣除營運成本（燃油、港口費、管理費）</span></span>
<span class="line"><span>毛利（Gross Margin）</span></span>
<span class="line"><span>    ↓ 扣除固定營運費用</span></span>
<span class="line"><span>EBITDA</span></span>
<span class="line"><span>    ↓ 扣除折舊、利息、稅賦</span></span>
<span class="line"><span>淨利（Net Income）</span></span></code></pre></div><h3 id="關鍵傳導特徵" tabindex="-1">關鍵傳導特徵 <a class="header-anchor" href="#關鍵傳導特徵" aria-label="Permalink to &quot;關鍵傳導特徵&quot;">​</a></h3><ol><li><strong>滯後效應</strong>：合約運價調整通常有 1–2 個月滯後，即期運價波動會先反映在當月營收</li><li><strong>成本刚性</strong>：船舶折舊、 crew 薪資等固定成本佔比高，運價小幅波動對毛利影響被放大</li><li><strong>燃油套期保值</strong>：大型航商透過燃油掉期合約對沖部分成本，可緩衝油價波動</li></ol><hr><h2 id="📈-2026-年貨櫃航運獲利狀況" tabindex="-1">📈 2026 年貨櫃航運獲利狀況 <a class="header-anchor" href="#📈-2026-年貨櫃航運獲利狀況" aria-label="Permalink to &quot;📈 2026 年貨櫃航運獲利狀況&quot;">​</a></h2><h3 id="承運人營運利潤率-2026-q1" tabindex="-1">承運人營運利潤率（2026 Q1） <a class="header-anchor" href="#承運人營運利潤率-2026-q1" aria-label="Permalink to &quot;承運人營運利潤率（2026 Q1）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>公司</th><th>預估營運利潤率</th><th>備註</th></tr></thead><tbody><tr><td>MSC（地中海航運）</td><td>~12–15%</td><td>全球最大，規模優勢明顯</td></tr><tr><td>Maersk（馬士基）</td><td>~10–12%</td><td>垂直整合供應鏈，穩定性較高</td></tr><tr><td>CMA CGM（達飛）</td><td>~8–10%</td><td>紅海繞航增加營收但成本也上升</td></tr><tr><td>Hapag-Lloyd（赫伯羅特）</td><td>~9–11%</td><td>跨大西洋航線受益於運價上漲</td></tr><tr><td>ONE（陽明/川崎/商船三井）</td><td>~7–9%</td><td>跨太平洋航線佔比高</td></tr><tr><td><strong>行業平均</strong></td><td><strong>~9.9%</strong></td><td>較 2025 Q2 的 14% EBIT 明顯下滑</td></tr></tbody></table><h3 id="運價與獲利關聯分析" tabindex="-1">運價與獲利關聯分析 <a class="header-anchor" href="#運價與獲利關聯分析" aria-label="Permalink to &quot;運價與獲利關聯分析&quot;">​</a></h3><ul><li><strong>2024 年</strong>：SCFI 高點 3,650 點時，主要航商 EBITDA 利潤率達 25–35%</li><li><strong>2025 年</strong>：SCFI 回落至 ~1,300–1,800 點，利潤率降至 5–12%</li><li><strong>2026 年</strong>：SCFI 回升至 ~1,954 點，但新船交付壓力使利潤率維持在 8–12%</li></ul><h3 id="_2026-年運價驅動因素" tabindex="-1">2026 年運價驅動因素 <a class="header-anchor" href="#_2026-年運價驅動因素" aria-label="Permalink to &quot;2026 年運價驅動因素&quot;">​</a></h3><table tabindex="0"><thead><tr><th>因素</th><th>影響方向</th><th>說明</th></tr></thead><tbody><tr><td>紅海繞航好望角</td><td>⬆️ 利多</td><td>增加航行時間 10–15 天，吸收過剩運力</td></tr><tr><td>新船交付（3.8%）</td><td>⬇️ 利空</td><td>運力增速超過需求增速（2.5%）</td></tr><tr><td>停航/減班控制</td><td>⬆️ 利多</td><td>主要承運人主動取消 5–10% 航次</td></tr><tr><td>旺季提前備貨</td><td>⬆️ 利多</td><td>关税不確定性促使出口前置</td></tr><tr><td>EU ETS 碳成本</td><td>⬇️ 利空</td><td>2026 年起 100% 排放需購買配額</td></tr></tbody></table><hr><h2 id="🔍-合約價-vs-即期價的獲利影響" tabindex="-1">🔍 合約價 vs 即期價的獲利影響 <a class="header-anchor" href="#🔍-合約價-vs-即期價的獲利影響" aria-label="Permalink to &quot;🔍 合約價 vs 即期價的獲利影響&quot;">​</a></h2><ul><li><strong>合約運價</strong>：通常佔承運人營收 60–80%，提供收入穩定性</li><li><strong>即期運價</strong>：佔 20–40%，波動大但利潤空間高</li><li><strong>2026 年趨勢</strong>：合約價與即期價差距收窄，承運人更依賴合約價維持基本獲利</li><li><strong>混合策略</strong>：大型託貨人採用「長約 + 即期」混合模式，降低價格波動風險</li></ul><hr><h2 id="📊-附加費對獲利的貢獻" tabindex="-1">📊 附加費對獲利的貢獻 <a class="header-anchor" href="#📊-附加費對獲利的貢獻" aria-label="Permalink to &quot;📊 附加費對獲利的貢獻&quot;">​</a></h2><ul><li><strong>GRI（綜合運費調整）</strong>：2026 年 5 月多家公司實施 GRI，跨大西洋航線每 FEU 增加 $400–$800</li><li><strong>PSS（旺季附加費）</strong>：跨太平洋航線每 FEU 增加 $1,500–$2,000</li><li><strong>EFS（緊急燃油附加費）</strong>：MSC 跨大西洋每 FEU $644，美西每 FEU $467</li><li>附加費佔承運人總營收的 15–25%，是維持利潤的重要工具</li></ul><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>iContainers (2026-05): 全球貨櫃運價預測與承運人利潤率分析</li><li>SP Global (2026-02): 2026 年海運展望——運價走軟但波動持續</li><li>Fitch Ratings (2025-08): 全球航運前景惡化分析</li><li>Global Maritime Hub (2026-05): 承運人營運利潤率下滑至 9.9%</li><li>Drewry WCI (2026-05-07): 世界貨櫃指數 $2,286/40ft</li></ol>`,24)])])}const _=a(e,[["render",l]]);export{g as __pageData,_ as default};
